def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    term = ((ratio - a) ** 7) / (a * b * 1.1 + 0.9)
                    priority += term * np.cos(ratio * b / (a + 2)) * np.exp(-b/(a+1))
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.8
            if bin_cap < item * 0.5:
                priority += np.log1p((item * bin_cap) ** 2) * 6
            else:
                priority -= np.exp(-1.5 * ratio) * 5.5
        elif 5 < ratio <= 8:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    val = ((ratio - p) ** 4) * np.sin(ratio * p * 1.1) / (q + 0.7)
                    priority += np.tanh(val) * 1.5
            priority += np.log(ratio) * 13 - np.tanh(ratio - 5) * 3
            if (i * int(item)) % 7 == 0:
                priority *= np.sqrt(bin_cap + 2)
            else:
                priority /= np.sqrt(bin_cap + 4)
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 16):
                s += ((ratio - 2) ** r) / (r * 2.3) * np.cos(r * ratio * 1.2)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(3 * (5 - ratio)) * 2
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1.5) ** m) / m
            if bin_cap < item * 0.75:
                priority += np.sqrt(item / (bin_cap + 0.3)) * 5
        elif 1 <= ratio < 2:
            s1 = 0
            for n in range(1, 13):
                s1 += ((2 - ratio) ** n) / (n ** 2 + 1.2)
            s2 = 0
            for k in range(1, 8):
                s2 += np.sin(ratio * k * 3.5) / (k + 0.5)
            priority = s1 + s2 + np.exp(-1.2 / (ratio + 0.1))
            if (i + int(item)) % 5 == 0:
                priority += np.log1p(bin_cap * item) * 3.7
            else:
                priority -= np.exp(-ratio * 1.8) * 3.2
            for t in range(1, 5):
                priority += np.sin(t * ratio * i * 1.3) * ((ratio - 0.9) ** t) / t * 1.1
        elif 0.5 <= ratio < 1:
            s = 0
            for u in range(1, 18):
                s += ((1 - ratio) ** u) / (u * 4.7)
            priority = s * 0.85
            if (i * int(item * 2.1)) % 6 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.6) * 0.9
            if bin_cap < item * 0.4:
                priority += np.sqrt(item * bin_cap) * 4.3
        elif 0.2 <= ratio < 0.5:
            s = 0
            for w in range(1, 20):
                s += ((0.5 - ratio) ** w) / (w * 5.3) * np.cos(w * ratio * 3.1)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.8) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.6
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 2.3) * 4.8
            for z in range(1, 10):
                priority += ((0.5 - ratio) ** z) / (z * 8) * np.cos(item * z * 1.4)
        else:
            s = 0
            for v in range(1, 15):
                s += ((0.2 - ratio) ** v) / (v * 6) * np.sin(v * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5.2
            for q in range(1, 9):
                priority += ((0.2 - ratio) ** q) / (q * 9) * np.cos(item * q * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 7
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.75
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.75
        priorities[i] = priority
    return priorities
